import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Introducing Predictive Aggregate Measurement (PAM)","description":"","frontmatter":{"title":"Introducing Predictive Aggregate Measurement (PAM)","slug":"introducing-predictive-aggregate-measurement-pam"},"headers":[],"relativePath":"account-hub/introducing-predictive-aggregate-measurement-pam.md","filePath":"account-hub/introducing-predictive-aggregate-measurement-pam.md"}'),n={name:"account-hub/introducing-predictive-aggregate-measurement-pam.md"};function o(s,e,c,d,l,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<p>Learn about Branch&#39;s new privacy-focused, aggregate-based attribution system: PAM!</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Predictive Aggregate Measurement (PAM) is a new Branch feature that helps marketers navigate the challenge of gaining meaningful attribution insights within an ever-evolving privacy landscape.</p><p>As the name implies, PAM attribution relies on aggregate-based analytics for users that have opted-out of tracking, and employs several layers of data precautions meant to prevent individual user identification.</p><p>With PAM, marketers can feel confident that they&#39;re getting a set of attribution data that&#39;s highly relevant to their campaigns and that would not be available otherwise, while still maintaining a commitment to user privacy standards.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><p>Use the resources below to gain a more comprehensive understanding of PAM.</p><h4 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h4><p>Learn more about PAM in our detailed <a href="./predictive-aggregate-measurement.html">guide</a>, which also includes <a href="./predictive-aggregate-measurement.html#implementation">implementation steps</a>.</p><h4 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>PAM is part of the Essentials tier of Branch&#39;s Performance product.</p><p>See all the other compelling and powerful features related to attribution insights included in this tier on the Help Center Pricing <a href="./packaging.html#performance-essentials-tier">page</a>.</p><h2 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h2><p>To access PAM data and start gaining valuable attribution information, contact our <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">sales team</a> to get started!</p>',14)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
